import React, { useState } from 'react';

const ITEMS = [
  { id: 'home', icon: '🏠', label: 'Home' },
  { id: 'search', icon: '🔍', label: 'Search' },
  {
    id: 'lib',
    icon: '📚',
    label: 'Library',
    children: [
      { id: 'songs', label: 'Songs' },
      { id: 'albums', label: 'Albums' },
    ],
  },
  { id: 'settings', icon: '⚙️', label: 'Settings' },
];

export default function Sidebar() {
  const [collapsed, setCollapsed] = useState(false);
  const [openGroups, setOpenGroups] = useState(() => new Set(['lib']));
  const [active, setActive] = useState('home');

  const toggleGroup = (id) =>
    setOpenGroups((s) => {
      const n = new Set(s);
      if (n.has(id)) n.delete(id);
      else n.add(id);
      return n;
    });

  const row = (extra) => ({
    display: 'flex',
    alignItems: 'center',
    gap: 12,
    padding: '10px 16px',
    cursor: 'pointer',
    whiteSpace: 'nowrap',
    ...extra,
  });

  return (
    <div style={{ display: 'flex', height: 320 }}>
      <aside style={{ width: collapsed ? 64 : 220, transition: 'width 0.2s ease', background: '#0f172a', color: '#e2e8f0', overflow: 'hidden' }}>
        <button
          onClick={() => setCollapsed((c) => !c)}
          aria-label={collapsed ? 'Expand' : 'Collapse'}
          style={{ ...row(), width: '100%', border: 'none', background: 'none', color: '#94a3b8' }}
        >
          <span>{collapsed ? '»' : '«'}</span>
          {!collapsed && <span>Collapse</span>}
        </button>

        {ITEMS.map((item) => (
          <div key={item.id}>
            <div
              onClick={() => (item.children ? toggleGroup(item.id) : setActive(item.id))}
              style={row({ background: active === item.id ? '#1e293b' : 'transparent' })}
            >
              <span style={{ fontSize: 18 }}>{item.icon}</span>
              {!collapsed && <span style={{ flex: 1 }}>{item.label}</span>}
              {!collapsed && item.children && <span>{openGroups.has(item.id) ? '▾' : '▸'}</span>}
            </div>
            {!collapsed && item.children && openGroups.has(item.id) &&
              item.children.map((c) => (
                <div
                  key={c.id}
                  onClick={() => setActive(c.id)}
                  style={row({ paddingLeft: 44, fontSize: 14, background: active === c.id ? '#1e293b' : 'transparent' })}
                >
                  {c.label}
                </div>
              ))}
          </div>
        ))}
      </aside>

      <main style={{ flex: 1, padding: 20 }}>
        <h2>Active: {active}</h2>
        <p>Toggle the sidebar with the «/» button.</p>
      </main>
    </div>
  );
}

