import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface MenuItem { id: string; icon?: string; label: string; children?: MenuItem[]; }

@Component({
  selector: 'app-sidebar',
  template: `
    <div style="display: flex; height: 320px; font-family: sans-serif;">
      <aside
        [style.width.px]="collapsed ? 64 : 220"
        style="transition: width 0.2s ease; background: #0f172a; color: #e2e8f0; overflow: hidden;"
      >
        <button
          (click)="collapsed = !collapsed"
          [attr.aria-label]="collapsed ? 'Expand' : 'Collapse'"
          class="row"
          style="width: 100%; border: none; background: none; color: #94a3b8; font: inherit;"
        >
          <span>{{ collapsed ? '»' : '«' }}</span>
          <span *ngIf="!collapsed">Collapse</span>
        </button>

        <div *ngFor="let item of items">
          <div class="row" [style.background]="active === item.id ? '#1e293b' : 'transparent'" (click)="onItem(item)">
            <span style="font-size: 18px;">{{ item.icon }}</span>
            <span *ngIf="!collapsed" style="flex: 1;">{{ item.label }}</span>
            <span *ngIf="!collapsed && item.children">{{ openGroups.has(item.id) ? '▾' : '▸' }}</span>
          </div>
          <ng-container *ngIf="!collapsed && item.children && openGroups.has(item.id)">
            <div
              *ngFor="let c of item.children"
              class="row"
              (click)="active = c.id"
              [style.background]="active === c.id ? '#1e293b' : 'transparent'"
              style="padding-left: 44px; font-size: 14px;"
            >{{ c.label }}</div>
          </ng-container>
        </div>
      </aside>

      <main style="flex: 1; padding: 20px;">
        <h2>Active: {{ active }}</h2>
        <p>Toggle the sidebar with the «/» button.</p>
      </main>
    </div>
  `,
  styles: [`
    .row { display: flex; align-items: center; gap: 12px; padding: 10px 16px; cursor: pointer; white-space: nowrap; }
  `],
})
export class SidebarComponent {
  collapsed = false;
  active = 'home';
  openGroups = new Set<string>(['lib']);
  items: MenuItem[] = [
    { id: 'home', icon: '🏠', label: 'Home' },
    { id: 'search', icon: '🔍', label: 'Search' },
    {
      id: 'lib',
      icon: '📚',
      label: 'Library',
      children: [
        { id: 'songs', label: 'Songs' },
        { id: 'albums', label: 'Albums' },
      ],
    },
    { id: 'settings', icon: '⚙️', label: 'Settings' },
  ];

  toggleGroup(id: string): void {
    if (this.openGroups.has(id)) {
      this.openGroups.delete(id);
    } else {
      this.openGroups.add(id);
    }
  }

  onItem(item: MenuItem): void {
    if (item.children) {
      this.toggleGroup(item.id);
    } else {
      this.active = item.id;
    }
  }
}

@Component({
  selector: 'app-root',
  template: `<app-sidebar></app-sidebar>`,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, SidebarComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
